import{_ as n,H as a,f as t,i as o}from"./chunks/framework.BHvCMIhP.js";const h=JSON.parse('{"title":"非对称加密(RSA / DH / 椭圆曲线 / 后量子初探)","description":"","frontmatter":{},"headers":[],"relativePath":"securityLearning/06-非对称加密.md","filePath":"securityLearning/06-非对称加密.md","lastUpdated":1778496697000}'),p={name:"securityLearning/06-非对称加密.md"};function r(e,s,l,i,d,g){return a(),t("div",null,[...s[0]||(s[0]=[o(`<h1 id="非对称加密-rsa-dh-椭圆曲线-后量子初探" tabindex="-1">非对称加密(RSA / DH / 椭圆曲线 / 后量子初探) <a class="header-anchor" href="#非对称加密-rsa-dh-椭圆曲线-后量子初探" aria-label="Permalink to &quot;非对称加密(RSA / DH / 椭圆曲线 / 后量子初探)&quot;">​</a></h1><p>上一篇讲对称加密时,反复回避了一个问题——<strong>「AES 的那个 32 字节密钥,你和对方怎么先达成共识」</strong>。两个人面对面拿 U 盘拷贝当然可以,问题是 HTTPS 里你和某个从没见过的服务器,怎么在<strong>全程都可能被监听的信道</strong>上,凭空协商出一个<strong>双方都知道、攻击者却推不出来</strong>的对称密钥?这就是 1970 年代之前所有密码学家都觉得「<strong>这不可能</strong>」的问题——直到 Diffie / Hellman / Merkle / Rivest / Shamir / Adleman 几个人在 1976-1977 年用纯数学把这件事干成,<strong>整个现代互联网的底座才搭起来</strong>。</p><blockquote><p>一句话先记住:<strong>非对称加密 = 「单向门」的数学化</strong> —— 「正着算容易,反着算难到现实里做不到」的数学陷阱(大数分解 / 离散对数 / 椭圆曲线点乘),让一个人能<strong>公开</strong>自己的公钥,任何人都能用它加密 / 验签,<strong>只有持有私钥的人能解密 / 签名</strong>。它不是对称加密的「升级版」,而是<strong>用来解决对称加密无法解决的问题</strong>——密钥分发 + 身份认证 + 不可抵赖。<strong>真实系统里两者永远配合使用</strong>:非对称解决&quot;开局&quot;,对称负责&quot;主体&quot;,这是 TLS / SSH / Signal / 几乎所有现代加密协议的通用结构。</p></blockquote><hr><h2 id="一、问题-对称密钥怎么交换" tabindex="-1">一、问题:对称密钥怎么交换 <a class="header-anchor" href="#一、问题-对称密钥怎么交换" aria-label="Permalink to &quot;一、问题:对称密钥怎么交换&quot;">​</a></h2><h3 id="_1-1-一个-鸡生蛋-的死结" tabindex="-1">1.1 一个&quot;鸡生蛋&quot;的死结 <a class="header-anchor" href="#_1-1-一个-鸡生蛋-的死结" aria-label="Permalink to &quot;1.1 一个&quot;鸡生蛋&quot;的死结&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Alice 想给 Bob 发密文,需要 AES 密钥 K</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>但传 K 给 Bob 需要&quot;安全信道&quot;</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>如果有安全信道,Alice 直接传明文就行了啊?</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>死循环</span></span></code></pre></div><p><strong>这是 1970 年代以前的密码学绝境</strong>——所有方案都假设「双方事先有共享密钥」,但现实里:</p><ul><li><strong>军方</strong>:每月派信使送密码本,<strong>线下</strong>交付</li><li><strong>银行</strong>:专人送 PIN 信封到客户家</li><li><strong>大使馆</strong>:外交邮袋送 one-time pad</li><li><strong>互联网</strong>:<strong>没法做</strong> —— 你和某个未曾谋面的网站,凭什么先约好密钥?</li></ul><p>如果非对称加密没被发明出来,<strong>今天根本不会有 HTTPS、电商、网银,所有「线上不见面交易」的场景都成立不了</strong>。</p><h3 id="_1-2-非对称加密的灵感-单向函数" tabindex="-1">1.2 非对称加密的灵感:单向函数 <a class="header-anchor" href="#_1-2-非对称加密的灵感-单向函数" aria-label="Permalink to &quot;1.2 非对称加密的灵感:单向函数&quot;">​</a></h3><p>数学上有一类操作:<strong>正算容易,反算难</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>正向(简单):</span></span>
<span class="line"><span>   3 × 7 = 21          (1 ns)</span></span>
<span class="line"><span>   123 × 457 = 56211   (10 ns)</span></span>
<span class="line"><span>   两个 1024-bit 质数相乘 = 一个 2048-bit 数(几 μs)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>反向(困难):</span></span>
<span class="line"><span>   56211 = ? × ?       (几秒能试出来)</span></span>
<span class="line"><span>   2048-bit 数 = ? × ? (现代最强算力 + 最佳算法,需要 10⁹ 年)</span></span></code></pre></div><p>「<strong>大数分解</strong>」就是一个<strong>经典的单向函数候选</strong>。如果我能造出一种加密,<strong>加密用 <code>公开的&quot;乘积&quot;</code>,解密需要 <code>保密的&quot;因子&quot;</code></strong>,就完成了「公开可加密、私密才能解」的不对称结构——这正是 RSA 的核心思想。</p><blockquote><p><strong>「单向门」的本质不是&quot;绝对不可逆&quot;,而是&quot;反向所需的算力远超攻击者预算&quot;</strong>。所有现代密码学都建立在「<strong>计算复杂度差距足够大</strong>」的假设上——一旦算法或硬件突破(量子计算机),整个根基就要重建。</p></blockquote><hr><h2 id="二、rsa-大数分解的工程化" tabindex="-1">二、RSA:大数分解的工程化 <a class="header-anchor" href="#二、rsa-大数分解的工程化" aria-label="Permalink to &quot;二、RSA:大数分解的工程化&quot;">​</a></h2><h3 id="_2-1-数学直觉-不堆公式" tabindex="-1">2.1 数学直觉(不堆公式) <a class="header-anchor" href="#_2-1-数学直觉-不堆公式" aria-label="Permalink to &quot;2.1 数学直觉(不堆公式)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 随机选两个大质数 p, q(例如各 1024 bit)</span></span>
<span class="line"><span>2. 计算 n = p × q                  → n 是 2048 bit</span></span>
<span class="line"><span>3. 选一个公开指数 e(常用 65537)</span></span>
<span class="line"><span>4. 算出私有指数 d(满足某个数论条件)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>公钥 = (n, e)                       任何人都能拿到</span></span>
<span class="line"><span>私钥 = (n, d) 或者 (p, q, d)        只有你自己有</span></span></code></pre></div><p>加密 / 签名的运算就是<strong>模幂</strong>:<code>c = m^e mod n</code>,解密就是 <code>m = c^d mod n</code>。<strong>安全性的全部根基是</strong>:</p><blockquote><p>「<strong>知道 n 反推 p、q</strong>」这件事,在 n = 2048 bit 下,<strong>没人会</strong>。</p></blockquote><p>如果哪天有人能在合理时间里分解 2048-bit 的 n,<strong>全世界所有 RSA 加密的旧数据一夜被解开</strong>。这就是为什么 NSA 等机构会<strong>囤积加密流量</strong>——「现在解不开,等技术够了再说」(harvest now, decrypt later)。</p><h3 id="_2-2-rsa-的两副面孔" tabindex="-1">2.2 RSA 的两副面孔 <a class="header-anchor" href="#_2-2-rsa-的两副面孔" aria-label="Permalink to &quot;2.2 RSA 的两副面孔&quot;">​</a></h3><table tabindex="0"><thead><tr><th>用途</th><th>流程</th><th>谁加密 / 签</th><th>谁解密 / 验</th></tr></thead><tbody><tr><td><strong>加密</strong></td><td>A 发密文给 B</td><td>A 用 <strong>B 的公钥</strong> 加密</td><td>B 用 <strong>B 的私钥</strong> 解密</td></tr><tr><td><strong>签名</strong></td><td>A 签一份文档</td><td>A 用 <strong>A 的私钥</strong> 签</td><td>所有人用 <strong>A 的公钥</strong> 验</td></tr></tbody></table><p><strong>两件不同的事,用同一套数学</strong>——这也是新手最容易混的:「公钥加密 / 私钥签名」<strong>方向是反的</strong>,不能套同一个心智。</p><h3 id="_2-3-pkcs-1-v1-5-padding-历史灾难" tabindex="-1">2.3 PKCS#1 v1.5 padding:历史灾难 <a class="header-anchor" href="#_2-3-pkcs-1-v1-5-padding-历史灾难" aria-label="Permalink to &quot;2.3 PKCS#1 v1.5 padding:历史灾难&quot;">​</a></h3><p>RSA 不能直接加密 <code>m</code>——必须先做 <strong>padding</strong>(填充)。原因有二:</p><ol><li><strong>小消息会被秒解</strong>:<code>m^e mod n</code>,如果 <code>m^e &lt; n</code>,直接开 e 次方就出来了</li><li><strong>相同消息加密两次密文一样</strong>:不引入随机性会泄漏模式</li></ol><p>1993 年 RSA 实验室给出的 padding 方案叫 <strong>PKCS#1 v1.5</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>加密时填充结构:</span></span>
<span class="line"><span>0x00 || 0x02 || &lt;随机字节 ≥ 8&gt; || 0x00 || &lt;真实消息&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>解密时检查:</span></span>
<span class="line"><span>开头是 0x00 0x02 吗?</span></span>
<span class="line"><span>找到第一个 0x00 分隔符吗?</span></span>
<span class="line"><span>真实消息长度合理吗?</span></span></code></pre></div><p><strong>问题</strong>:这个检查的&quot;成功 / 失败&quot;信息<strong>会泄漏给攻击者</strong>——Bleichenbacher 在 1998 年发现,通过观察服务器对&quot;恶意密文&quot;的响应(返回错误 / 不返回 / 报错码不同),<strong>可以一点点反推明文</strong>——史称 <strong>Bleichenbacher 攻击</strong>,简称 <strong>百万消息攻击</strong>(因为需要约 100 万次猜测)。</p><p>更可怕的是,<strong>这个漏洞反复回潮</strong>:</p><ul><li>1998 Bleichenbacher 原版</li><li>2003 Klima / Pokorny / Rosa(针对 SSL/TLS)</li><li>2017 <strong>ROBOT</strong>(Return Of Bleichenbacher&#39;s Oracle Threat)—— Facebook / PayPal / 思科都中招</li><li>2023 还有变种(Marvin Attack)</li></ul><p><strong>结论</strong>:<strong>PKCS#1 v1.5 是个伪需求工程</strong>——本来想让格式校验&quot;安全&quot;,结果安全成了 oracle。<strong>现代系统应当用 OAEP</strong>(Optimal Asymmetric Encryption Padding),它用一对 hash 把消息和随机数充分混淆,<strong>没有可观测的格式差异给攻击者作信号</strong>。</p><h3 id="_2-4-rsa-的工程现实" tabindex="-1">2.4 RSA 的工程现实 <a class="header-anchor" href="#_2-4-rsa-的工程现实" aria-label="Permalink to &quot;2.4 RSA 的工程现实&quot;">​</a></h3><ul><li><strong>2048 bit 是当前底线</strong>,1024 bit 已被认为不安全(NIST 2030 年要求 ≥3072)</li><li><strong>加密慢</strong>:RSA-2048 加密一次约 0.1 ms,<strong>ECC-256 是它的 10-20 倍快</strong>(详见后文)</li><li><strong>不能加密大数据</strong>:RSA-2048 一次只能加 ~245 bytes(OAEP 后),<strong>所以永远只用来加密&quot;对称密钥&quot;,再用 AES 加密真正的 payload</strong></li><li><strong>私钥文件很大</strong>:RSA-2048 私钥约 1.2 KB,ECC-256 私钥只有 ~120 字节</li></ul><blockquote><p><strong>新系统不要再用 RSA 加密</strong>,除非兼容老协议;签名场景也尽量迁移到 Ed25519。RSA 在 2030+ 会逐步退场。</p></blockquote><hr><h2 id="三、diffie-hellman-史上最优雅的密钥交换" tabindex="-1">三、Diffie-Hellman:史上最优雅的密钥交换 <a class="header-anchor" href="#三、diffie-hellman-史上最优雅的密钥交换" aria-label="Permalink to &quot;三、Diffie-Hellman:史上最优雅的密钥交换&quot;">​</a></h2><h3 id="_3-1-一张图讲完" tabindex="-1">3.1 一张图讲完 <a class="header-anchor" href="#_3-1-一张图讲完" aria-label="Permalink to &quot;3.1 一张图讲完&quot;">​</a></h3><p>DH 的天才之处在于:<strong>Alice 和 Bob 不传密钥,但能算出同一个密钥</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>全网公开:大质数 p,生成元 g</span></span>
<span class="line"><span>            ↓</span></span>
<span class="line"><span>        ┌───────┴───────┐</span></span>
<span class="line"><span>        ↓               ↓</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    Alice                            Bob</span></span>
<span class="line"><span>    ─────                            ───</span></span>
<span class="line"><span>    选秘密 a                          选秘密 b</span></span>
<span class="line"><span>    算 A = g^a mod p                 算 B = g^b mod p</span></span>
<span class="line"><span></span></span>
<span class="line"><span>           ── A ──────────────────→</span></span>
<span class="line"><span>           ←──────────────── B ──</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    收到 B                            收到 A</span></span>
<span class="line"><span>    算 K = B^a mod p                 算 K = A^b mod p</span></span>
<span class="line"><span></span></span>
<span class="line"><span>         K = (g^b)^a = g^(ab) mod p = (g^a)^b</span></span>
<span class="line"><span>              ↑                            ↑</span></span>
<span class="line"><span>         Alice 算出的                  Bob 算出的</span></span>
<span class="line"><span>         共享密钥                       共享密钥(相同)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    ↑                                 ↑</span></span>
<span class="line"><span>    监听者看到了 p, g, A, B</span></span>
<span class="line"><span>    但要从 A 反推 a 需要解&quot;离散对数&quot;</span></span>
<span class="line"><span>    在 p 足够大时,他做不到 → 算不出 K</span></span></code></pre></div><p><strong>核心数学事实</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>正向(简单):a 已知 → 算 g^a mod p</span></span>
<span class="line"><span>反向(困难):g^a mod p 已知 → 推 a</span></span>
<span class="line"><span>            ↑</span></span>
<span class="line"><span>       这就是「离散对数问题」</span></span>
<span class="line"><span>       和大数分解一样,目前没有多项式时间解</span></span></code></pre></div><h3 id="_3-2-前向保密-forward-secrecy-pfs" tabindex="-1">3.2 前向保密(Forward Secrecy / PFS) <a class="header-anchor" href="#_3-2-前向保密-forward-secrecy-pfs" aria-label="Permalink to &quot;3.2 前向保密(Forward Secrecy / PFS)&quot;">​</a></h3><p>DH 最革命性的副作用:<strong>每次会话都新生成临时的 a、b</strong> —— 这次握手用完就丢。即使将来:</p><ul><li>服务器的<strong>长期私钥被泄漏</strong></li><li>攻击者<strong>囤积了过去所有密文</strong></li></ul><p>他<strong>也解不开旧会话</strong> —— 因为旧会话的密钥是 <code>g^(ab) mod p</code>,而 a、b 早就被销毁,<strong>无法重建</strong>。</p><p>这就是 <strong>PFS(Perfect / Forward Secrecy)</strong> 的本质:<strong>「过去的安全不依赖于现在的私钥」</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>没 PFS(旧 RSA 密钥交换):</span></span>
<span class="line"><span>   会话密钥 = 用服务器 RSA 公钥加密发过去</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>   服务器私钥泄了 → 历史所有会话全暴露</span></span>
<span class="line"><span></span></span>
<span class="line"><span>有 PFS(DHE / ECDHE):</span></span>
<span class="line"><span>   会话密钥 = 临时 DH 算出来,握手后销毁</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>   服务器私钥泄了 → 只影响&quot;以后想冒充服务器&quot;,历史会话仍然安全</span></span></code></pre></div><blockquote><p><strong>现代 TLS 1.3 强制要求 PFS</strong> —— 全部用 ECDHE,RSA 密钥交换被砍掉。这是 Snowden 爆料后整个行业的集体反应——「大国可以囤密文等密钥」,所以<strong>必须从协议层保证「囤了也白囤」</strong>。</p></blockquote><h3 id="_3-3-dh-的工程化变种" tabindex="-1">3.3 DH 的工程化变种 <a class="header-anchor" href="#_3-3-dh-的工程化变种" aria-label="Permalink to &quot;3.3 DH 的工程化变种&quot;">​</a></h3><table tabindex="0"><thead><tr><th>名称</th><th>含义</th><th>用途</th></tr></thead><tbody><tr><td><strong>DH</strong></td><td>经典 DH,模乘法群</td><td>已基本废弃,慢</td></tr><tr><td><strong>DHE</strong></td><td>Ephemeral DH,每次新 a/b</td><td>TLS 1.2 的 PFS 选项,慢</td></tr><tr><td><strong>ECDH</strong></td><td>椭圆曲线版</td><td>静态长期密钥用</td></tr><tr><td><strong>ECDHE</strong></td><td>椭圆曲线 + 临时密钥</td><td><strong>TLS 1.3 主力</strong>,快 + PFS</td></tr><tr><td><strong>X25519</strong></td><td>用 Curve25519 的 ECDHE</td><td><strong>现代默认</strong>,Signal / WireGuard / SSH 都用</td></tr></tbody></table><h3 id="_3-4-dh-自身的陷阱-中间人" tabindex="-1">3.4 DH 自身的陷阱:<strong>中间人</strong> <a class="header-anchor" href="#_3-4-dh-自身的陷阱-中间人" aria-label="Permalink to &quot;3.4 DH 自身的陷阱:**中间人**&quot;">​</a></h3><p>DH 解决了&quot;算出共享密钥&quot;,<strong>但完全不解决&quot;对方是谁&quot;</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Alice ──A──→ [Mallory] ──A&#39;──→ Bob</span></span>
<span class="line"><span>Alice ←──B&#39;── [Mallory] ←──B── Bob</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Mallory 和 Alice 协商出一个密钥 K1</span></span>
<span class="line"><span>Mallory 和 Bob   协商出一个密钥 K2</span></span>
<span class="line"><span>Alice 和 Bob 各自以为在和对方说话,其实都在和 Mallory 说话</span></span></code></pre></div><p><strong>DH 必须配合身份认证</strong>(数字签名 / 证书 / 预共享密钥),否则裸跑就是中间人靶子。这就是 TLS 里 ECDHE <strong>加上</strong> RSA / ECDSA 签名的原因——签名做认证,DH 做密钥协商,<strong>分工明确</strong>。</p><hr><h2 id="四、椭圆曲线密码-ecc-为什么-256-bit-≈-3072-bit-rsa" tabindex="-1">四、椭圆曲线密码(ECC):为什么 256-bit ≈ 3072-bit RSA <a class="header-anchor" href="#四、椭圆曲线密码-ecc-为什么-256-bit-≈-3072-bit-rsa" aria-label="Permalink to &quot;四、椭圆曲线密码(ECC):为什么 256-bit ≈ 3072-bit RSA&quot;">​</a></h2><h3 id="_4-1-不数学-讲心智" tabindex="-1">4.1 不数学,讲心智 <a class="header-anchor" href="#_4-1-不数学-讲心智" aria-label="Permalink to &quot;4.1 不数学,讲心智&quot;">​</a></h3><p>ECC 不是「另一种加密算法」,而是<strong>换了一个数学结构</strong>来做单向函数。RSA 在「整数模 n 的乘法群」上玩,ECC 在「椭圆曲线点的加法群」上玩。具体曲线长什么样不重要,<strong>你需要记住的只有一件事</strong>:</p><blockquote><p>在椭圆曲线上,「<strong>反推</strong>」问题(ECDLP — 椭圆曲线离散对数问题)<strong>更难</strong>——已知的最快算法是**√n 量级**(Pollard&#39;s rho),而整数离散对数 / 大数分解都有<strong>亚指数级算法</strong>(GNFS,数域筛法)。</p></blockquote><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>攻击 RSA-2048    ≈ 攻击 ECC-224</span></span>
<span class="line"><span>攻击 RSA-3072    ≈ 攻击 ECC-256        ← 当前主流</span></span>
<span class="line"><span>攻击 RSA-15360   ≈ 攻击 ECC-512</span></span></code></pre></div><p><strong>同等安全强度下,ECC 密钥小一个数量级</strong>——这带来三个工程上的巨大优势:</p><ol><li><strong>更快</strong>:运算量小 10-20 倍</li><li><strong>更小</strong>:证书 / 签名 / 私钥都小</li><li><strong>更省电</strong>:移动端 / IoT 友好</li></ol><h3 id="_4-2-rsa-vs-ecc-vs-ed25519-工程对比" tabindex="-1">4.2 RSA vs ECC vs Ed25519 工程对比 <a class="header-anchor" href="#_4-2-rsa-vs-ecc-vs-ed25519-工程对比" aria-label="Permalink to &quot;4.2 RSA vs ECC vs Ed25519 工程对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>RSA-2048</th><th>ECC-256 (secp256r1)</th><th>Ed25519</th></tr></thead><tbody><tr><td><strong>安全强度</strong></td><td>~112 bit</td><td>~128 bit</td><td>~128 bit</td></tr><tr><td><strong>公钥大小</strong></td><td>256 B</td><td>64 B</td><td>32 B</td></tr><tr><td><strong>私钥大小</strong></td><td>~1.2 KB</td><td>~120 B</td><td>32 B</td></tr><tr><td><strong>签名大小</strong></td><td>256 B</td><td>64 B</td><td>64 B</td></tr><tr><td><strong>密钥生成</strong></td><td>~100 ms</td><td>~0.1 ms</td><td>~0.05 ms</td></tr><tr><td><strong>签名速度</strong></td><td>~1 ms</td><td>~0.5 ms</td><td><strong>~0.05 ms</strong></td></tr><tr><td><strong>验签速度</strong></td><td><strong>~0.05 ms</strong></td><td>~1 ms</td><td>~0.15 ms</td></tr><tr><td><strong>加密 / KEX</strong></td><td>慢 + 不推荐</td><td>不直接加密(用 ECDH)</td><td>不加密(只签名)</td></tr><tr><td><strong>量子安全</strong></td><td>否</td><td>否</td><td>否</td></tr><tr><td><strong>常数时间实现</strong></td><td>难</td><td><strong>难</strong>(secp 系列)</td><td><strong>天然容易</strong>(设计目标)</td></tr><tr><td><strong>推荐场景</strong></td><td>兼容老系统</td><td>美标 / FIPS 合规</td><td><strong>新系统默认</strong></td></tr></tbody></table><blockquote><p>注:RSA <strong>验签</strong>比签名快得多(公开指数小,模幂便宜),这是 RSA 唯一仍有竞争力的场景——<strong>大量验签 + 偶尔签名</strong>的 CA 体系。</p></blockquote><h3 id="_4-3-ecc-也有-坑曲线" tabindex="-1">4.3 ECC 也有&quot;坑曲线&quot; <a class="header-anchor" href="#_4-3-ecc-也有-坑曲线" aria-label="Permalink to &quot;4.3 ECC 也有&quot;坑曲线&quot;&quot;">​</a></h3><p>ECC 的安全性<strong>严重依赖曲线参数选取</strong>。<strong>不是所有曲线都安全</strong>:</p><ul><li>早年 NSA 推动的 <strong>Dual_EC_DRBG</strong> 被发现是个<strong>后门</strong>——参数里藏了 NSA 才知道的&quot;陷门&quot;</li><li>一些低质量曲线在小子群攻击 / 不变 j-不变量攻击下崩溃</li></ul><p><strong>所以工业界只用经过广泛审计的几条曲线</strong>——下一节展开。</p><hr><h2 id="五、曲线之争-secp256r1-x25519-ed25519" tabindex="-1">五、曲线之争:secp256r1 / X25519 / Ed25519 <a class="header-anchor" href="#五、曲线之争-secp256r1-x25519-ed25519" aria-label="Permalink to &quot;五、曲线之争:secp256r1 / X25519 / Ed25519&quot;">​</a></h2><h3 id="_5-1-三条主流曲线" tabindex="-1">5.1 三条主流曲线 <a class="header-anchor" href="#_5-1-三条主流曲线" aria-label="Permalink to &quot;5.1 三条主流曲线&quot;">​</a></h3><table tabindex="0"><thead><tr><th>曲线</th><th>别名</th><th>设计者</th><th>用途</th><th>政治色彩</th></tr></thead><tbody><tr><td><strong>secp256r1</strong></td><td>P-256, prime256v1</td><td>NIST / NSA</td><td>ECDH / ECDSA</td><td>美标,FIPS 合规必需</td></tr><tr><td><strong>Curve25519</strong></td><td>X25519 (ECDH)</td><td>Daniel J. Bernstein</td><td>密钥交换</td><td>&quot;反 NSA&quot;派系</td></tr><tr><td><strong>Edwards25519</strong></td><td>Ed25519 (签名)</td><td>Daniel J. Bernstein</td><td>签名</td><td>同上</td></tr></tbody></table><h3 id="_5-2-为什么-x25519-ed25519-后来居上" tabindex="-1">5.2 为什么 X25519 / Ed25519 后来居上 <a class="header-anchor" href="#_5-2-为什么-x25519-ed25519-后来居上" aria-label="Permalink to &quot;5.2 为什么 X25519 / Ed25519 后来居上&quot;">​</a></h3><p>DJB(Daniel J. Bernstein,「djb」)在 2005 年提出 Curve25519,核心思路是「<strong>让正确实现变得容易,让错误实现变得不可能</strong>」。这有几个工程后果:</p><ol><li><strong>天然常数时间</strong>:不需要刻意写&quot;防时序攻击&quot;的代码,数学结构本身让分支都没有</li><li><strong>没有&quot;无效点&quot;陷阱</strong>:任何 32 字节都是合法公钥,免疫&quot;小子群攻击&quot;</li><li><strong>不需要随机数验签</strong>(Ed25519 用确定性签名,签名不再依赖 RNG 质量)</li><li><strong>参数完全公开透明</strong>(基点 / 余因子全是数学常数,<strong>没有 NSA 留缝隙的空间</strong>)</li></ol><p>而 NIST 曲线被诟病的核心是:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NIST P-256 的参数 c 来自一个 SHA-1 哈希</span></span>
<span class="line"><span>SHA-1 的输入是个&quot;随机的种子&quot;——但种子的选择没有解释</span></span>
<span class="line"><span>NSA 是否预先试出&quot;对自己有利的种子&quot;,至今没法证伪</span></span></code></pre></div><blockquote><p>Snowden 之后,「<strong>不信任美方曲线</strong>」成为西方安全社区主流情绪。<strong>Signal / WireGuard / SSH / TLS 1.3 全部默认 X25519 + Ed25519</strong>,Apple iOS / Android 也广泛采用。<strong>新项目选 25519 系</strong>,除非合规强制要 P-256。</p></blockquote><h3 id="_5-3-工程口诀" tabindex="-1">5.3 工程口诀 <a class="header-anchor" href="#_5-3-工程口诀" aria-label="Permalink to &quot;5.3 工程口诀&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>要密钥交换       → X25519</span></span>
<span class="line"><span>要签名           → Ed25519</span></span>
<span class="line"><span>要兼容老 TLS / 合规 → secp256r1 + ECDSA / SHA-256</span></span>
<span class="line"><span>要兼容上古系统    → RSA-2048(逐步淘汰)</span></span></code></pre></div><hr><h2 id="六、后量子密码学-pqc-2030-年要换的算法" tabindex="-1">六、后量子密码学(PQC):2030 年要换的算法 <a class="header-anchor" href="#六、后量子密码学-pqc-2030-年要换的算法" aria-label="Permalink to &quot;六、后量子密码学(PQC):2030 年要换的算法&quot;">​</a></h2><h3 id="_6-1-量子计算威胁了什么" tabindex="-1">6.1 量子计算威胁了什么 <a class="header-anchor" href="#_6-1-量子计算威胁了什么" aria-label="Permalink to &quot;6.1 量子计算威胁了什么&quot;">​</a></h3><p><strong>所有基于「整数分解」或「离散对数」的算法,被 Shor 算法在量子计算机上多项式时间破解</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>受影响(全军覆没):</span></span>
<span class="line"><span>   RSA / DSA / DH         ← Shor 算法</span></span>
<span class="line"><span>   ECC / ECDH / ECDSA     ← Shor 算法</span></span>
<span class="line"><span>   Ed25519 / X25519       ← Shor 算法</span></span>
<span class="line"><span></span></span>
<span class="line"><span>相对安全(只是密钥要加倍):</span></span>
<span class="line"><span>   AES                    ← Grover 算法,效果 = 把 256-bit 降到 128-bit</span></span>
<span class="line"><span>   SHA-2 / SHA-3          ← Grover,影响有限</span></span></code></pre></div><p><strong>对称加密在量子时代只需把密钥从 128-bit 加到 256-bit</strong>,问题不大。<strong>非对称加密则要从头换</strong>。</p><h3 id="_6-2-现在是-2030-年之前的什么时点" tabindex="-1">6.2 现在是 2030 年之前的什么时点 <a class="header-anchor" href="#_6-2-现在是-2030-年之前的什么时点" aria-label="Permalink to &quot;6.2 现在是 2030 年之前的什么时点&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2015  NIST 启动 PQC 标准化</span></span>
<span class="line"><span>2022  第一轮入围结果公布</span></span>
<span class="line"><span>2024  NIST 发布最终标准:</span></span>
<span class="line"><span>        FIPS 203 — ML-KEM(基于 Kyber,密钥封装)</span></span>
<span class="line"><span>        FIPS 204 — ML-DSA(基于 Dilithium,签名)</span></span>
<span class="line"><span>        FIPS 205 — SLH-DSA(基于 SPHINCS+,哈希签名,备份方案)</span></span>
<span class="line"><span>2025  Cloudflare / Google Chrome / Apple iMessage 已经在生产环境</span></span>
<span class="line"><span>      启用「ML-KEM + X25519」**混合密钥交换**</span></span>
<span class="line"><span>2030+ 量子计算机预期能威胁实用 RSA / ECC 的时间窗口</span></span></code></pre></div><p><strong>两个时间线在赛跑</strong>:量子机的进展 vs 全行业迁移的进度。<strong>没人能确定哪个先到,但「现在就开始混合」是唯一稳妥的工程姿势</strong>——因为攻击者今天就在囤密文。</p><h3 id="_6-3-ml-kem-kyber-与-ml-dsa-dilithium-心智" tabindex="-1">6.3 ML-KEM(Kyber)与 ML-DSA(Dilithium)心智 <a class="header-anchor" href="#_6-3-ml-kem-kyber-与-ml-dsa-dilithium-心智" aria-label="Permalink to &quot;6.3 ML-KEM(Kyber)与 ML-DSA(Dilithium)心智&quot;">​</a></h3><p>不展开数学,<strong>只记三个心智</strong>:</p><ol><li><strong>基于&quot;格&quot;(Lattice)问题</strong>:学习带误差(LWE)/ 模块 LWE / 短整数解(SIS)——这类问题被认为<strong>量子机也搞不定</strong></li><li><strong>密钥变大很多</strong>:ML-KEM 公钥 ~800 B,私钥 ~1.6 KB —— <strong>比 X25519 的 32 B 大 25-50 倍</strong></li><li><strong>运算速度</strong>反而比 RSA 快,和 ECC 同级</li></ol><p><strong>主要痛点</strong>:<strong>握手包变胖</strong>。TLS 1.3 一个 ClientHello 从 ~250 字节涨到 ~1500+ 字节,<strong>可能撑爆 MTU 触发分片</strong>——已知一些老旧中间盒会出问题(称为 <strong>TLS PQC ossification</strong>)。Cloudflare 2023-2024 的实际部署数据显示影响 &lt; 1%,但<strong>这个工程问题是真实的</strong>。</p><h3 id="_6-4-混合模式-hybrid" tabindex="-1">6.4 混合模式(Hybrid) <a class="header-anchor" href="#_6-4-混合模式-hybrid" aria-label="Permalink to &quot;6.4 混合模式(Hybrid)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>传统单一握手:</span></span>
<span class="line"><span>   ECDHE (X25519) → 共享密钥</span></span>
<span class="line"><span></span></span>
<span class="line"><span>PQC 单一握手(激进):</span></span>
<span class="line"><span>   ML-KEM → 共享密钥</span></span>
<span class="line"><span>   ↑</span></span>
<span class="line"><span>   万一 Kyber 数学被攻破怎么办?</span></span>
<span class="line"><span>   (新算法还没经过几十年实战检验)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>PQC + 经典混合(稳健 ✓):</span></span>
<span class="line"><span>   X25519 算出 K1</span></span>
<span class="line"><span>   ML-KEM 算出 K2</span></span>
<span class="line"><span>   最终密钥 = KDF(K1 || K2)</span></span>
<span class="line"><span>   ↑</span></span>
<span class="line"><span>   只要 X25519 和 Kyber 至少有一个还安全,会话就安全</span></span></code></pre></div><p><strong>现阶段所有部署都是混合</strong>——「<strong>用 Kyber 防量子,用 X25519 防 Kyber 出问题</strong>」,工程稳健性优先。</p><blockquote><p>Chrome 自 2023 年起对部分流量启用 X25519MLKEM768。看你的 TLS 连接里 KEX 如果出现 <code>X25519MLKEM768</code>,那就是混合模式生效。</p></blockquote><hr><h2 id="七、工程视角-什么场景用什么算法" tabindex="-1">七、工程视角:什么场景用什么算法 <a class="header-anchor" href="#七、工程视角-什么场景用什么算法" aria-label="Permalink to &quot;七、工程视角:什么场景用什么算法&quot;">​</a></h2><h3 id="_7-1-场景速查表" tabindex="-1">7.1 场景速查表 <a class="header-anchor" href="#_7-1-场景速查表" aria-label="Permalink to &quot;7.1 场景速查表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>推荐算法</th><th>备注</th></tr></thead><tbody><tr><td><strong>TLS 1.3 密钥交换</strong></td><td>X25519(或加 ML-KEM 混合)</td><td>默认主力</td></tr><tr><td><strong>TLS 服务端身份签名</strong></td><td>ECDSA-P256 / Ed25519 / RSA-2048</td><td>看 CA 支持,Let&#39;s Encrypt 已支持 ECDSA</td></tr><tr><td><strong>SSH 服务器密钥</strong></td><td><strong>Ed25519</strong>(新机器全默认)</td><td>旧 RSA 主机密钥可以换</td></tr><tr><td><strong>JWT 签名</strong></td><td>EdDSA(Ed25519) / ES256(ECDSA)</td><td><strong>HS256 是对称,小项目可用;别用 RS256</strong></td></tr><tr><td><strong>Git 提交签名</strong></td><td>Ed25519</td><td>GitHub / GitLab 全支持</td></tr><tr><td><strong>代码签名(企业)</strong></td><td>RSA-3072 或 ECDSA-P384</td><td>受合规约束,可能强制 RSA</td></tr><tr><td><strong>IoT 设备签名</strong></td><td>Ed25519</td><td>资源受限友好</td></tr><tr><td><strong>加密文件 / 邮件</strong></td><td>age / minisign(底层用 X25519 / Ed25519)</td><td><strong>别用 OpenPGP/GPG</strong>——太复杂、太多陷阱</td></tr><tr><td><strong>客户端到客户端 E2EE</strong></td><td>X25519 + Ed25519(Signal Protocol)</td><td>配合 Double Ratchet</td></tr><tr><td><strong>后量子准备</strong></td><td>X25519MLKEM768 混合</td><td>2025+ 关键基础设施开始上</td></tr></tbody></table><h3 id="_7-2-决策树" tabindex="-1">7.2 决策树 <a class="header-anchor" href="#_7-2-决策树" aria-label="Permalink to &quot;7.2 决策树&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>要做新系统的密钥交换?</span></span>
<span class="line"><span>├── 受 FIPS / 合规约束? → secp256r1 (ECDH-P256)</span></span>
<span class="line"><span>├── 担心 2030+ 量子威胁? → X25519 + ML-KEM 混合</span></span>
<span class="line"><span>└── 其他全部场景       → X25519</span></span>
<span class="line"><span></span></span>
<span class="line"><span>要做新系统的数字签名?</span></span>
<span class="line"><span>├── 受 FIPS 约束?       → ECDSA-P256</span></span>
<span class="line"><span>├── 需要长期归档(&gt;20 年)? → 考虑 SLH-DSA(基于哈希,最保守)</span></span>
<span class="line"><span>└── 其他全部场景       → Ed25519</span></span>
<span class="line"><span></span></span>
<span class="line"><span>要解密 / 加密?</span></span>
<span class="line"><span>└── 几乎不要直接用非对称加密大消息</span></span>
<span class="line"><span>    用「KEM + 对称加密」模式:</span></span>
<span class="line"><span>       非对称协商 / 封装出 32 字节密钥</span></span>
<span class="line"><span>       AES-GCM 加密真正的数据</span></span></code></pre></div><h3 id="_7-3-跟非对称加密相关的几条铁律" tabindex="-1">7.3 跟非对称加密相关的几条铁律 <a class="header-anchor" href="#_7-3-跟非对称加密相关的几条铁律" aria-label="Permalink to &quot;7.3 跟非对称加密相关的几条铁律&quot;">​</a></h3><ol><li><strong>永远不要自己实现</strong> —— RSA 实现陷阱超过 30 个,ECC 更多;<strong>用 libsodium / Tink / Ring / BoringSSL</strong></li><li><strong>永远不要复用密钥对</strong>于不同用途——签名密钥不能拿去加密,反之亦然</li><li><strong>永远不要从一个公钥反推另一个公钥的&quot;关系&quot;</strong> —— 这是分层确定性密钥(HD wallets)的设计陷阱</li><li><strong>永远要把非对称加密包在协议里,别裸用</strong> —— 协议层(TLS / Noise / Signal Protocol)处理了一堆你没意识到的边角(防重放、防降级、防中间人……)</li><li><strong>私钥必须存在 HSM / KMS / Secure Enclave</strong> —— 服务器明文存 .pem 文件就是定时炸弹</li></ol><hr><h2 id="八、踩坑提醒" tabindex="-1">八、踩坑提醒 <a class="header-anchor" href="#八、踩坑提醒" aria-label="Permalink to &quot;八、踩坑提醒&quot;">​</a></h2><ol><li><strong>以为 RSA 比 AES 更安全</strong>——「非对称就是高级版」是错觉,<strong>两者解决完全不同的问题,而且非对称 1000 倍慢</strong></li><li><strong>以为公钥能加密任意大数据</strong>——RSA-2048 一次只能加 ~245 字节,<strong>实践中必须用 KEM 模式</strong>(非对称包对称密钥)</li><li><strong>以为换大密钥就安全</strong>——RSA-4096 vs RSA-2048 安全性提升远不及 ECC-256;<strong>算法选择比密钥长度重要</strong></li><li><strong>以为 ECDH 自带身份认证</strong>——不,DH 解决 KEX 但 <strong>不解决&quot;对方是谁&quot;</strong>,必须配签名 / 证书</li><li><strong>以为 PFS 是 TLS 自带的</strong>——TLS 1.2 默认握手套件可能不是 ECDHE,<strong>要显式配置</strong>;TLS 1.3 才强制</li><li><strong>以为 Ed25519 「太新不可靠」</strong>——它 2011 年发明,2015 年标准化,<strong>Signal / WhatsApp / SSH 用了十年没出过事</strong>,远比&quot;古老&quot; RSA 的实现稳</li><li><strong>以为后量子还很遥远</strong>—— harvest-now-decrypt-later 已经是现实,<strong>国家级攻击者今天就在囤密文</strong></li><li><strong>以为换 PQC 就够了</strong>——PQC 算法本身仍可能有数学缺陷被未来发现,<strong>混合模式才是稳健选择</strong></li><li><strong>以为 ECDSA 总是常数时间</strong>——P-256 的某些实现不是,<strong>Ed25519 才天生常数时间</strong>;时序攻击在 2018-2024 还在不断爆 ECDSA 漏洞</li><li><strong>以为非对称加密能完全替代 PKI</strong>——<strong>不能</strong>——非对称加密只解决&quot;算法&quot;,但&quot;谁的公钥是真的&quot;必须靠<strong>证书 / 信任锚</strong> —— 这是下一篇的话题</li></ol><hr><p>下一篇:<code>07-数字签名与证书.md</code>——讲清楚「<strong>签名 vs 加密 vs MAC 是三件不同的事</strong>」(很多新手用 RSA 加密做&quot;签名&quot;是大错)、X.509 证书的链式信任为什么会断、<strong>为什么 CA 被信任而不是别的角色</strong>、证书透明度(CT)日志如何让伪造证书&quot;无处藏身&quot;、SSH 没有 CA 它怎么解决身份问题(TOFU 模型),以及 Let&#39;s Encrypt 这种自动化 CA 是怎么把&quot;几百块一张证书&quot;变成&quot;免费、90 天一换&quot;的新基础设施的。</p>`,114)])])}const u=n(p,[["render",r]]);export{h as __pageData,u as default};
